import {useNavigate} from "react-router-dom"

function ProductCard({product}){

const nav = useNavigate()

return(
<div className="card" onClick={()=>nav("/product/"+product.name)}>

<img src={product.image}/>

<h3>{product.name}</h3>

<p>⭐ {product.rating}</p>

<div className="priceBox">From ₹{product.stores[0].price}</div>

</div>
)
}

export default ProductCard
